    using TypeId = uint64_t;

    struct Void
    {
        constexpr bool operator==(Void) const { return true; }
        constexpr bool operator!=(Void) const { return false; }
    };

    enum class DeclKind : uint16_t
    {
        None,

        Attribute,
        Const,
        Enum,
        File,
        Interface,
        Struct,
    };

    enum class PointerKind : uint16_t
    {
        Struct = 0,
        List = 1,
    };

    template <TypeId Id> struct DeclInfo;

    #define HE_SCHEMA_DECL_INFO(id, parentId, kind, fieldCount, dataWordSize, pointerCount) \
        template <> struct ::he::schema::DeclInfo<id> { \
            static constexpr ::he::schema::TypeId Id = id; \
            static constexpr ::he::schema::TypeId ParentId = parentId; \
            static constexpr ::he::schema::DeclKind Kind = ::he::schema::DeclKind::kind; \
            static constexpr uint16_t DataFieldCount = fieldCount; \
            static constexpr uint16_t DataWordSize = dataWordSize; \
            static constexpr uint16_t PointerCount = pointerCount; \
            static const ::he::schema::Word* DefaultValue; \
            static const ::he::schema::Word* RawSchema; \
            static const ::he::schema::Declaration& GetSchema(); \
        }

    // --------------------------------------------------------------------------------------------
    // The MSB of IDs is always set. This has two desireable effects:
    // - Since @ is used for field ordinals and IDs it can be easy to mix them up. Someone may
    //  attempt to write an ID for a type declaration manually (like @2) which would be
    //  problematic since IDs are intended to be globally unique.
    // - Because the top bit is always set IDs can always be printed as 32 hex digits without
    //  any leading zeroes.
    constexpr TypeId TypeIdFlag = (1ull << 63);

    enum class ElementSize : uint16_t
    {
        Void = 0,
        Bit = 1,
        Byte = 2,
        TwoBytes = 3,
        FourBytes = 4,
        EightBytes = 5,
        Pointer = 6,
        Composite = 7,

        _Count,
    };

    enum class TypeKind : uint16_t
    {
        Void = 0,
        Bool = 1,
        Int8 = 2,
        Int16 = 3,
        Int32 = 4,
        Int64 = 5,
        Uint8 = 6,
        Uint16 = 7,
        Uint32 = 8,
        Uint64 = 9,
        Float32 = 10,
        Float64 = 11,
        Array = 12,
        Blob = 13,
        String = 14,
        List = 15,
        Enum = 16,
        Struct = 17,
        Interface = 18,
        AnyPointer = 19,
    };

    struct Type;

    struct Brand
    {
        struct Scope
        {
            ~Scope();

            TypeId scopeId{ 0 };
            Vector<Type*> params{};
        };

        Vector<Scope> scopes{};
    };

    struct Type
    {
        Type() = default;
        Type(Type&) = delete;
        Type(Type&& x);
        ~Type();

        Type& operator=(Type&) = delete;
        Type& operator=(Type&& x);

        TypeKind kind{ TypeKind::Void };

        // union
        // {
            struct
            {
                TypeId paramScopeId{ 0 };
                uint16_t paramIndex{ 0 }; // Index of the type param in the scope's typeParams list
            } any_;

            struct
            {
                uint16_t size{ 0 };
                Type* elementType{ nullptr };
            } array_;

            struct
            {
                Type* elementType{ nullptr };
            } list_;

            struct
            {
                TypeId id{ 0 };
                Brand brand{};
            } enum_;

            struct
            {
                TypeId id{ 0 };
                Brand brand{};
            } interface_;

            struct
            {
                TypeId id{ 0 };
                Brand brand{};
            } struct_;
        // };
    };

    struct Value
    {
        ~Value();

        TypeKind kind{ TypeKind::Void };

        union
        {
            Void v;
            bool b;
            int8_t i8;
            int16_t i16;
            int32_t i32;
            int64_t i64;
            uint8_t u8;
            uint16_t u16;
            uint32_t u32;
            uint64_t u64{ 0 };
            float f32;
            double f64;

            // AnyPointer array;
            // Blob blob;
            // String str;
            // AnyPointer list;
            uint16_t enum_;
            // AnyPointer struct;
            Void interface;
            // AnyPointer any;
        };

        Vector<Value*> array{};
        Vector<uint8_t> blob{};
        String str{};
        Vector<Value*> list{};

        struct StructValue
        {
            String fieldName{};
            Value* value{ nullptr };
        };
        Vector<StructValue> struct_{};
    };

    struct Attribute
    {
        TypeId id{ 0 };
        Value value{};
    };

    struct Field
    {
        String name{};
        uint16_t declOrder{ 0 }; // implicit based on order it was written in the schema file
        uint16_t unionTag{ 0 };  // tag value for this field if it is in a union

        bool isGroup{ false };
        bool isUnion{ false };

        Vector<Attribute> attributes{};

        // For group/union fields
        TypeId typeId{ 0 };

        // For normal fields, not groups/unions
        uint16_t ordinal{ 0 };  // explicit ordinal value specified using @
        uint16_t index{ 0 };    // implicit index of the field in its section

        // For data fields this is the offset in units of the field size from the beginning of
        // the data section (after the metadata). For example, for a uint32 field multiply this
        // by 4 to get the byte offset.
        // Always zero for pointer fields.
        uint32_t dataOffset{ 0 };

        Type type{};
        Value defaultValue{};
    };

    struct Enumerator
    {
        String name{};
        uint16_t declOrder{ 0 }; // implicit based on order it was written in the schema file
        uint16_t ordinal{ 0 };   // explicit ordinal value specified using @

        Vector<Attribute> attributes{};
    };

    struct Method
    {
        String name{};
        uint16_t declOrder{ 0 }; // implicit based on order it was written in the schema file
        uint16_t ordinal{ 0 };   // explicit ordinal value specified using @

        TypeId paramStruct{ 0 };
        TypeId resultStruct{ 0 };

        Vector<Attribute> attributes{};
        Vector<String> typeParams{};
    };

    struct SourceInfo
    {
        String docComment{};
        String file{};
        uint32_t line{ 0 };
        uint32_t column{ 0 };
    };

    struct Declaration
    {
        DeclKind kind{ DeclKind::None };

        TypeId id{ 0 };
        TypeId parentId{ 0 };
        String name{};

        Vector<Attribute> attributes{};
        Vector<String> typeParams{};
        Vector<Declaration> children{};
        Vector<Declaration> forwards{};

        SourceInfo source{};

        // union
        // {
            struct
            {

            } file_;

            struct
            {
                Type type{};

                bool targetsAttribute{ false };
                bool targetsConst{ false };
                bool targetsEnum{ false };
                bool targetsEnumerator{ false };
                bool targetsField{ false };
                bool targetsFile{ false };
                bool targetsInterface{ false };
                bool targetsMethod{ false };
                bool targetsParameter{ false };
                bool targetsStruct{ false };
            } attribute_;

            struct
            {
                Type type{};
                Value value{};
            } const_;

            struct
            {
                Vector<Enumerator> enumerators{};
            } enum_;

            struct
            {
                Type super{};
                Vector<Method> methods{};
            } interface_;

            struct
            {
                uint16_t dataWordSize{ 0 };
                uint16_t pointerCount{ 0 };
                bool isGroup{ false };
                bool isUnion{ false };
                bool isAutoGenerated{ false }; // when true this type was generated by the parser, generally for interface method params/result.
                uint32_t unionTagOffset{ 0 }; // offset to union tag, in 2-byte units, if isUnion is true.
                Vector<Field> fields{};
            } struct_;
        // };
    };

    struct Import
    {
        ~Import();

        String path{};
        struct SchemaFile* schema{ nullptr };
    };

    struct SchemaFile
    {
        SchemaFile() {}

        Declaration root{};
        Vector<Import> imports{};
        Vector<Attribute> attributes{};
    };

    // // --------------------------------------------------------------------------------------------
    constexpr bool IsSignedIntegral(TypeKind k)
    {
        switch (k)
        {
            case TypeKind::Int8:
            case TypeKind::Int16:
            case TypeKind::Int32:
            case TypeKind::Int64:
                return true;
            default:
                return false;
        }
    }

    constexpr bool IsUnsignedIntegral(TypeKind k)
    {
        switch (k)
        {
            case TypeKind::Uint8:
            case TypeKind::Uint16:
            case TypeKind::Uint32:
            case TypeKind::Uint64:
                return true;
            default:
                return false;
        }
    }

    constexpr bool IsIntegral(TypeKind k)
    {
        return IsSignedIntegral(k) || IsUnsignedIntegral(k);
    }

    constexpr bool IsFloat(TypeKind k)
    {
        switch (k)
        {
            case TypeKind::Float32:
            case TypeKind::Float64:
                return true;
            default:
                return false;
        }
    }

    constexpr bool IsArithmetic(TypeKind k)
    {
        return IsIntegral(k) || IsFloat(k);
    }

    constexpr bool IsPointer(const Type& type)
    {
        switch (type.kind)
        {
            case TypeKind::Array:
                return IsPointer(*type.array_.elementType);

            case TypeKind::Blob:
            case TypeKind::String:
            case TypeKind::List:
            case TypeKind::Struct:
            case TypeKind::Interface:
            case TypeKind::AnyPointer:
                return true;

            default:
                return false;
        }
    }

    // Returns the bit alignment requirements for a type
    constexpr uint32_t GetTypeAlign(const Type& type)
    {
        switch (type.kind)
        {
            case TypeKind::Void: return 0;
            case TypeKind::Bool: return 1;
            case TypeKind::Int8: return 8;
            case TypeKind::Int16: return 16;
            case TypeKind::Int32: return 32;
            case TypeKind::Int64: return 64;
            case TypeKind::Uint8: return 8;
            case TypeKind::Uint16: return 16;
            case TypeKind::Uint32: return 32;
            case TypeKind::Uint64: return 64;
            case TypeKind::Float32: return 32;
            case TypeKind::Float64: return 64;
            case TypeKind::Array: return GetTypeAlign(*type.array_.elementType);
            case TypeKind::Blob: return 64; // pointer
            case TypeKind::String: return 64; // pointer
            case TypeKind::List: return 64; // pointer
            case TypeKind::Enum: return 16; // uint16
            case TypeKind::Struct: return 64; // pointer
            case TypeKind::Interface: return 64; // pointer
            case TypeKind::AnyPointer: return 64; // pointer
        }

        HE_ASSERT(false, "Unknown type kind");
        return 0;
    }

    // Returns the size of a type in bits
    constexpr uint32_t GetTypeSize(const Type& type)
    {
        const uint32_t align = GetTypeAlign(type);
        const uint32_t count = type.kind == TypeKind::Array ? type.array_.size : 1;
        return align * count;
    }

    struct IdHasher
    {
        size_t operator()(TypeId id) const { return static_cast<size_t>(id); }
    };
